function main({ input }) {
  // 使用正则表达式找到"(https://www.36kr.com/information/other/)"之后到"查看更多"之前的内容
  const regex = /\(https:\/\/www\.36kr\.com\/information\/other\/\)\s*(.*?)(?=查看更多)/s;
  const match = input.match(regex);

  // 提取匹配到的内容
  let extractedContent;
  if (match && match[1]) {
    extractedContent = match[1].trim();
  } else {
    extractedContent = "无法提取内容";
  }

  return {
    result: extractedContent,
  };
}

function main({input}) {
  // 解析输入的日期时间字符串
  const currentDate = new Date(input.split(' ')[0] + 'T' + input.split(' ')[1]);

  // 创建前一天的日期对象
  const previousDate = new Date(currentDate);
  previousDate.setDate(previousDate.getDate() - 1);

  // 格式化前一天的日期为YYYY-MM-DD格式
  const prevYear = previousDate.getFullYear();
  const prevMonth = String(previousDate.getMonth() + 1).padStart(2, '0');
  const prevDay = String(previousDate.getDate()).padStart(2, '0');
  const formattedPrevDate = `${prevYear}-${prevMonth}-${prevDay}`;

  // 格式化当天的日期为YYYY-MM-DD格式
  const currYear = currentDate.getFullYear();
  const currMonth = String(currentDate.getMonth() + 1).padStart(2, '0');
  const currDay = String(currentDate.getDate()).padStart(2, '0');
  const formattedCurrDate = `${currYear}-${currMonth}-${currDay}`;

  // 生成最终结果字符串
  const resultString = `${formattedPrevDate}..${formattedCurrDate}`;

  return {
    result: resultString,
  }
}
